using UnityEngine;
using UnityEngine.InputSystem;

[RequireComponent(typeof(Rigidbody))]
public class PlayerControllerWithEvents : MonoBehaviour
{
    [Header("Movement")]
    [Tooltip("Multiplier applied to input when applying torque/force")]
    public float moveSpeed = 6f;
    [Tooltip("If true, applies torque to roll the ball. Otherwise applies linear force.")]
    public bool useTorque = true;

    [Header("Jump")]
    public float jumpForce = 5f;
    [Tooltip("Distance to check beneath the ball to consider it grounded")]
    public float groundCheckDistance = 0.55f;
    [Tooltip("Layer mask used for ground checks")]
    public LayerMask groundLayers = ~0; // default to everything

    Rigidbody _rb;
    Vector2 _moveInput = Vector2.zero;

    void Awake()
    {
        _rb = GetComponent<Rigidbody>();
        // Ensure reasonable angular velocity for rolling responsiveness
        _rb.maxAngularVelocity = 20f;
    }

    // This method is called by the Input System (PlayerInput -> Invoke Unity Events)
    // Bind the "Move" action to this method in the PlayerInput inspector.
    public void OnMove(InputAction.CallbackContext ctx)
    {
        _moveInput = ctx.ReadValue<Vector2>();
    }

    // Bind the "Jump" action to this method in the PlayerInput inspector.
    public void OnJump(InputAction.CallbackContext ctx)
    {
        if (ctx.performed)
        {
            if (IsGrounded())
            {
                _rb.AddForce(Vector3.up * jumpForce, ForceMode.Impulse);
            }
        }
    }

    void FixedUpdate()
    {
        Vector3 move = new Vector3(_moveInput.x, 0f, _moveInput.y);

        if (move.sqrMagnitude < 1e-6f)
            return;

        if (useTorque)
        {
            // Apply torque perpendicular to movement to make the sphere roll naturally.
            Vector3 axis = Vector3.Cross(Vector3.up, move.normalized);
            float factor = move.magnitude * moveSpeed;
            Vector3 torque = axis * factor;
            _rb.AddTorque(torque, ForceMode.Acceleration);
        }
        else
        {
            _rb.AddForce(move * moveSpeed, ForceMode.Acceleration);
        }
    }

    bool IsGrounded()
    {
        // Raycast down from the center of the sphere
        return Physics.Raycast(transform.position, Vector3.down, groundCheckDistance, groundLayers);
    }

    // Optional: draw debug ray in editor
    void OnDrawGizmosSelected()
    {
        Gizmos.color = Color.yellow;
        Gizmos.DrawLine(transform.position, transform.position + Vector3.down * groundCheckDistance);
    }
}

using UnityEngine;

public class Pickup : MonoBehaviour
{
    [Tooltip("Value awarded when collected")]
    public int scoreValue = 1;
    [Tooltip("Optional effect to instantiate on collect")]
    public GameObject collectEffect;

    void Reset()
    {
        // Ensure this object has a trigger collider by default
        var col = GetComponent<Collider>();
        if (col == null)
        {
            gameObject.AddComponent<BoxCollider>().isTrigger = true;
        }
        else
        {
            col.isTrigger = true;
        }
    }

    void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Player"))
        {
            if (collectEffect != null)
                Instantiate(collectEffect, transform.position, Quaternion.identity);

            // Simple behavior: deactivate the pickup
            gameObject.SetActive(false);

            // Optionally notify a GameManager via messaging (if exists)
            // GameObject.FindObjectOfType<GameManager>()?.AddScore(scoreValue);
        }
    }
}

using UnityEngine;

[RequireComponent(typeof(Rigidbody))]
public class RollerPlayer : MonoBehaviour
{
    [Header("Movimento")]
    [SerializeField, Tooltip("Velocidade base (multiplica o torque aplicado)")]
    private float moveSpeed = 10f;
    [SerializeField, Tooltip("Multiplicador extra para o torque")]
    private float torqueMultiplier = 15f;
    [SerializeField, Tooltip("Máxima velocidade angular permitida (evita giro descontrolado)")]
    private float maxAngularVelocity = 50f;

    [Header("Input (Input Manager - padrão)")]
    [SerializeField, Tooltip("Nome do eixo horizontal (Input Manager)")]
    private string horizAxisName = "Horizontal";
    [SerializeField, Tooltip("Nome do eixo vertical (Input Manager)")]
    private string vertAxisName = "Vertical";

    [Header("Referências")]
    [SerializeField, Tooltip("Rigidbody da bola (será atribuído automaticamente se vazio)")]
    private Rigidbody rb;
    [SerializeField, Tooltip("Referência opcional da câmera. Se preenchida, o movimento será relativo à câmera")]
    private Transform cameraTransform;

    void Awake()
    {
        if (rb == null) rb = GetComponent<Rigidbody>();
        if (rb == null)
        {
            Debug.LogError("RollerPlayer: Rigidbody não encontrado. Adicione um Rigidbody ao GameObject.");
            enabled = false;
            return;
        }

        // Define limite de velocidade angular no Rigidbody para evitar rotações muito rápidas
        rb.maxAngularVelocity = maxAngularVelocity;
    }

    void FixedUpdate()
    {
        // Leitura simples de input pelo Input Manager (WASD / setas por padrão)
        float h = Input.GetAxis(horizAxisName);
        float v = Input.GetAxis(vertAxisName);

        Vector3 input = new Vector3(h, 0f, v);

        if (input.sqrMagnitude < 0.0001f)
            return;

        Vector3 move = input;

        // Se houver câmera informada, converte input para espaço do mundo relativo à câmera
        if (cameraTransform != null)
        {
            Vector3 forward = cameraTransform.forward;
            forward.y = 0f;
            forward.Normalize();
            Vector3 right = cameraTransform.right;
            right.y = 0f;
            right.Normalize();
            move = forward * v + right * h;
        }

        // Calcula um torque que faz a bola rolar na direção do input
        Vector3 torque = Vector3.Cross(Vector3.up, move).normalized * move.magnitude * moveSpeed * torqueMultiplier;

        // Aplica torque no Rigidbody (modo Acceleration para ser independente da massa)
        rb.AddTorque(torque, ForceMode.Acceleration);

        // Limita a velocidade angular para o valor configurado
        if (rb.angularVelocity.sqrMagnitude > maxAngularVelocity * maxAngularVelocity)
        {
            rb.angularVelocity = rb.angularVelocity.normalized * maxAngularVelocity;
        }
    }
}
